ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?dividend_percentage ?dividend_value WHERE {
  ?dividends a :Dividends .
  ?shares a :Shares .
  ?dividends p:hasShares ?shares .
  ?dividends p:Dividend_Percentage ?dividend_percentage .
  ?dividends p:Dividend_Value ?dividend_value .
  ?shares p:Stock ?stock_f .
  FILTER(STR(?stock_f) = "PQR Ltd.")
} }
  component: { SELECT ?dividend_percentage WHERE {
  ?dividends a :Dividends .
  ?shares a :Shares .
  ?dividends p:hasShares ?shares .
  ?dividends p:Dividend_Percentage ?dividend_percentage .
  ?shares p:Stock ?stock_f .
  FILTER(STR(?stock_f) = "PQR Ltd.")
} }
  component_2: { SELECT ?dividend_value WHERE {
  ?dividends a :Dividends .
  ?shares a :Shares .
  ?dividends p:hasShares ?shares .
  ?dividends p:Dividend_Value ?dividend_value .
  ?shares p:Stock ?stock_f .
  FILTER(STR(?stock_f) = "PQR Ltd.")
} }
}

PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?dividend_value WHERE {
  ?dividends a :Dividends .
